// --- HMAC signature validation (canonical JSON) ---
// Both sender and receiver must use sorted-key, compact JSON.
// Sender: json.dumps(payload, sort_keys=True, separators=(',', ':'))
// Receiver: JSON.stringify with sorted keys (below)
const crypto = require('crypto');
const secret = $env.N8N_WEBHOOK_SECRET;
const signature = $input.first().json.headers['x-webhook-signature'] || '';

// Recursively sort object keys for canonical JSON
function sortKeys(obj) {
  if (Array.isArray(obj)) return obj.map(sortKeys);
  if (obj !== null && typeof obj === 'object') {
    return Object.keys(obj).sort().reduce((acc, key) => {
      acc[key] = sortKeys(obj[key]);
      return acc;
    }, {});
  }
  return obj;
}

const body = $input.first().json.body;
const canonicalBody = JSON.stringify(sortKeys(body));
const expected = 'sha256=' + crypto.createHmac('sha256', secret).update(canonicalBody).digest('hex');

// Pre-check buffer length to prevent timingSafeEqual RangeError
const sigBuf = Buffer.from(signature);
const expBuf = Buffer.from(expected);
if (sigBuf.length !== expBuf.length || !crypto.timingSafeEqual(sigBuf, expBuf)) {
  return [{ json: { killed: 'true', reason: 'hmac_validation_failed' } }];
}

// Extract and validate payload
if (!body.suiteId || !body.officeId) {
  return [{ json: { killed: 'true', reason: 'missing_tenant_context' } }];
}

const requestId = 'intake-activation-' + Date.now() + '-' + Math.random().toString(36).slice(2, 8);
const correlationId = body.correlationId || ($input.first().json.headers['x-correlation-id']) || ('n8n-intake-activation-' + body.suiteId.slice(0, 8) + '-' + new Date().toISOString().slice(0, 10));
const payloadHash = crypto.createHash('sha256').update(JSON.stringify(sortKeys({ suiteId: body.suiteId, industry: body.industry }))).digest('hex');
const idempotencyKey = crypto.createHash('sha256').update(requestId + 'intake.activation' + payloadHash).digest('hex');

// Build setup tasks — all services auto-included (v3 onboarding)
const allServiceTasks = [
  { title: 'Connect your Stripe account', agent: 'quinn', service: 'Invoicing & Payments' },
  { title: 'Connect QuickBooks Online', agent: 'teressa', service: 'Bookkeeping' },
  { title: 'Set up your business email domain', agent: 'eli', service: 'Email Management' },
  { title: 'Connect Google Calendar', agent: 'nora', service: 'Scheduling & Calendar' },
  { title: 'Upload contract templates', agent: 'clara', service: 'Contract Management' },
  { title: 'Connect Gusto payroll', agent: 'milo', service: 'Payroll' },
  { title: 'Upload your logo and letterhead', agent: 'tec', service: 'Document Generation' },
  { title: 'Review your first industry brief', agent: 'adam', service: 'Research & Intelligence' },
  { title: 'Set up your business phone line', agent: 'sarah', service: 'Front Desk & Calls' },
  { title: 'Connect your bank accounts', agent: 'finn', service: 'Expense Tracking' },
  { title: 'Set up tax year preferences', agent: 'teressa', service: 'Tax Preparation' }
];

const tasks = allServiceTasks.map(t => ({
  suite_id: body.suiteId,
  office_id: body.officeId,
  title: t.title,
  assigned_agent: t.agent,
  status: 'pending',
  category: 'onboarding_setup',
  source_service: t.service,
  created_by: 'n8n-intake-activation',
  created_at: new Date().toISOString()
}));

return [{ json: {
  killed: 'false',
  requestId,
  correlationId,
  idempotencyKey,
  suiteId: body.suiteId,
  officeId: body.officeId,
  dateOfBirth: body.dateOfBirth || null,
  gender: body.gender || null,
  industry: body.industry || null,
  industrySpecialty: body.industrySpecialty || null,
  incomeRange: body.incomeRange || null,
  referralSource: body.referralSource || null,
  businessGoals: body.businessGoals || null,
  painPoint: body.painPoint || null,
  customerType: body.customerType || null,
  salesChannel: body.salesChannel || null,
  teamSize: body.teamSize || null,
  tasks,
  tasksCount: tasks.length,
  timestamp: new Date().toISOString()
} }];

